   565→    private void handleRestoringAndUpdatingTasks(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
   566→                                                 final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate,
   567→                                                 final Map<TaskId, RuntimeException> failedTasks) {
