   595→    private void handleTasksInStateUpdater(final Map<TaskId, Set<TopicPartition>> activeTasksToCreate,
   596→                                           final Map<TaskId, Set<TopicPartition>> standbyTasksToCreate,
   597→                                           final Map<Task, Set<TopicPartition>> tasksToRecycle,
   598→                                           final Set<Task> tasksToCloseCleanFromStateUpdater,
   599→                                           final Set<Task> tasksToCloseDirtyFromStateUpdater,
   600→                                           final Map<TaskId, RuntimeException> failedTasks) {
   601→        final Map<TaskId, Set<TopicPartition>> newInputPartitions = new HashMap<>();
   602→        final Map<TaskId, Set<TopicPartition>> standbyInputPartitions = new HashMap<>();
   603→        final Map<TaskId, Set<TopicPartition>> activeInputPartitions = new HashMap<>();
   604→        final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futuresForUpdatingInputPartitions = new LinkedHashMap<>();
   605→        final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futuresForActiveTasksToRecycle = new LinkedHashMap<>();
   606→        final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futuresForStandbyTasksToRecycle = new LinkedHashMap<>();
   607→        final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futuresForTasksToClose = new LinkedHashMap<>();
   608→        for (final Task task : stateUpdater.tasks()) {
   609→            final TaskId taskId = task.id();
   610→            if (activeTasksToCreate.containsKey(taskId)) {
   611→                if (task.isActive()) {
   612→                    if (!task.inputPartitions().equals(activeTasksToCreate.get(taskId))) {
   613→                        final CompletableFuture<StateUpdater.RemovedTaskResult> future = stateUpdater.remove(taskId);
   614→                        futuresForUpdatingInputPartitions.put(taskId, future);
   615→                        newInputPartitions.put(taskId, activeTasksToCreate.get(taskId));
   616→                    }
   617→                } else {
   618→                    final CompletableFuture<StateUpdater.RemovedTaskResult> future = stateUpdater.remove(taskId);
   619→                    futuresForStandbyTasksToRecycle.put(taskId, future);
   620→                    activeInputPartitions.put(taskId, activeTasksToCreate.get(taskId));
   621→                }
   622→                activeTasksToCreate.remove(taskId);
   623→            } else if (standbyTasksToCreate.containsKey(taskId)) {
   624→                if (task.isActive()) {
   625→                    final CompletableFuture<StateUpdater.RemovedTaskResult> future = stateUpdater.remove(taskId);
   626→                    futuresForActiveTasksToRecycle.put(taskId, future);
   627→                    standbyInputPartitions.put(taskId, standbyTasksToCreate.get(taskId));
   628→                }
   629→                standbyTasksToCreate.remove(taskId);
   630→            } else {
   631→                final CompletableFuture<StateUpdater.RemovedTaskResult> future = stateUpdater.remove(taskId);
   632→                futuresForTasksToClose.put(taskId, future);
   633→            }
   634→        }
   635→        updateInputPartitions(futuresForUpdatingInputPartitions, newInputPartitions, failedTasks);
   636→        addToActiveTasksToRecycle(futuresForActiveTasksToRecycle, standbyInputPartitions, tasksToRecycle, failedTasks);
   637→        addToStandbyTasksToRecycle(futuresForStandbyTasksToRecycle, activeInputPartitions, tasksToRecycle, failedTasks);
   638→        addToTasksToClose(futuresForTasksToClose, tasksToCloseCleanFromStateUpdater, tasksToCloseDirtyFromStateUpdater);
   639→    }
