   641→    private void updateInputPartitions(final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futures,
   642→                                       final Map<TaskId, Set<TopicPartition>> newInputPartitions,
   643→                                       final Map<TaskId, RuntimeException> failedTasks) {
   644→        getNonFailedTasks(futures, failedTasks).forEach(task -> {
   645→            task.updateInputPartitions(
   646→                newInputPartitions.get(task.id()),
   647→                topologyMetadata.nodeToSourceTopics(task.id())
   648→            );
   649→            stateUpdater.add(task);
   650→        });
