   654→                                           final Map<TaskId, Set<TopicPartition>> standbyInputPartitions,
   655→                                           final Map<Task, Set<TopicPartition>> tasksToRecycle,
   656→                                           final Map<TaskId, RuntimeException> failedTasks) {
