   667→    private Stream<Task> getNonFailedTasks(final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futures,
   668→                                           final Map<TaskId, RuntimeException> failedTasks) {
   669→        return futures.entrySet().stream()
   670→            .map(entry -> waitForFuture(entry.getKey(), entry.getValue()))
   671→            .filter(Objects::nonNull)
   672→            .map(removedTaskResult -> checkIfTaskFailed(removedTaskResult, failedTasks))
   673→            .filter(Objects::nonNull);
   674→    }
