   677→    private void addToTasksToClose(final Map<TaskId, CompletableFuture<StateUpdater.RemovedTaskResult>> futures,
   678→                                   final Set<Task> tasksToCloseCleanFromStateUpdater,
   679→                                   final Set<Task> tasksToCloseDirtyFromStateUpdater) {
   680→        futures.entrySet().stream()
   681→            .map(entry -> waitForFuture(entry.getKey(), entry.getValue()))
   682→            .filter(Objects::nonNull)
   683→            .forEach(removedTaskResult -> {
   684→                if (removedTaskResult.exception().isPresent()) {
   685→                    tasksToCloseDirtyFromStateUpdater.add(removedTaskResult.task());
   686→                } else {
   687→                    tasksToCloseCleanFromStateUpdater.add(removedTaskResult.task());
   688→                }
   689→            });
   690→    }
