   692→    private Task checkIfTaskFailed(final StateUpdater.RemovedTaskResult removedTaskResult,
   693→                                   final Map<TaskId, RuntimeException> failedTasks) {
   694→        final Task task = removedTaskResult.task();
   695→        if (removedTaskResult.exception().isPresent()) {
   696→            failedTasks.put(task.id(), removedTaskResult.exception().get());
   697→            tasks.addFailedTask(task);
   698→            return null;
   699→        }
   700→        return task;
