   703→    private StateUpdater.RemovedTaskResult waitForFuture(final TaskId taskId,
   704→                                                         final CompletableFuture<StateUpdater.RemovedTaskResult> future) {
   705→        final StateUpdater.RemovedTaskResult removedTaskResult;
   706→        try {
   707→            removedTaskResult = future.get();
   708→            if (removedTaskResult == null) {
   709→                throw new IllegalStateException("Task " + taskId + " was not found in the state updater. "
   710→                    + BUG_ERROR_MESSAGE);
   711→            }
   712→            return removedTaskResult;
   713→        } catch (final ExecutionException executionException) {
   714→            log.warn("An exception happened when removing task {} from the state updater. The task was added to the " +
   715→                    "failed task in the state updater: ",
   716→                taskId, executionException);
   717→            return null;
   718→        } catch (final InterruptedException shouldNotHappen) {
   719→            Thread.currentThread().interrupt();
   720→            log.error(INTERRUPTED_ERROR_MESSAGE, shouldNotHappen);
   721→            throw new IllegalStateException(INTERRUPTED_ERROR_MESSAGE, shouldNotHappen);
   722→        }
   723→    }
