   725→    private Map<TaskId, Set<TopicPartition>> pendingTasksToCreate(final Map<TaskId, Set<TopicPartition>> tasksToCreate) {
   726→        final Map<TaskId, Set<TopicPartition>> pendingTasks = new HashMap<>();
   727→        final Iterator<Map.Entry<TaskId, Set<TopicPartition>>> iter = tasksToCreate.entrySet().iterator();
   728→        while (iter.hasNext()) {
   729→            final Map.Entry<TaskId, Set<TopicPartition>> entry = iter.next();
   730→            final TaskId taskId = entry.getKey();
   731→            final boolean taskIsOwned = tasks.allTaskIds().contains(taskId)
   732→                || (stateUpdater != null && stateUpdater.tasks().stream().anyMatch(task -> task.id() == taskId));
   733→            if (taskId.topologyName() != null && !taskIsOwned && !topologyMetadata.namedTopologiesView().contains(taskId.topologyName())) {
   734→                log.info("Cannot create the assigned task {} since it's topology name cannot be recognized, will put it " +
   735→                        "aside as pending for now and create later when topology metadata gets refreshed", taskId);
   736→                pendingTasks.put(taskId, entry.getValue());
   737→                iter.remove();
   738→            }
   739→        }
   740→        return pendingTasks;
   741→    }
