   743→    private Map<TaskId, RuntimeException> closeAndRecycleTasks(final Map<Task, Set<TopicPartition>> tasksToRecycle,
   744→                                                               final Set<Task> tasksToCloseClean) {
   745→        final Map<TaskId, RuntimeException> taskCloseExceptions = new LinkedHashMap<>();
   746→        final Set<Task> tasksToCloseDirty = new TreeSet<>(Comparator.comparing(Task::id));
   747→
   748→        // for all tasks to close or recycle, we should first write a checkpoint as in post-commit
   749→        final List<Task> tasksToCheckpoint = new ArrayList<>(tasksToCloseClean);
   750→        tasksToCheckpoint.addAll(tasksToRecycle.keySet());
   751→        for (final Task task : tasksToCheckpoint) {
   752→            try {
   753→                // Note that we are not actually committing here but just check if we need to write checkpoint file:
   754→                // 1) for active tasks prepareCommit should return empty if it has committed during suspension successfully,
   755→                //    and their changelog positions should not change at all postCommit would not write the checkpoint again.
   756→                // 2) for standby tasks prepareCommit should always return empty, and then in postCommit we would probably
   757→                //    write the checkpoint file.
   758→                final Map<TopicPartition, OffsetAndMetadata> offsets = task.prepareCommit(true);
   759→                if (!offsets.isEmpty()) {
   760→                    log.error("Task {} should have been committed when it was suspended, but it reports non-empty " +
   761→                                    "offsets {} to commit; this means it failed during last commit and hence should be closed dirty",
   762→                            task.id(), offsets);
   763→
   764→                    tasksToCloseDirty.add(task);
   765→                } else if (!task.isActive()) {
   766→                    // For standby tasks, always try to first suspend before committing (checkpointing) it;
   767→                    // Since standby tasks do not actually need to commit offsets but only need to
   768→                    // flush / checkpoint state stores, so we only need to call postCommit here.
   769→                    task.suspend();
   770→
   771→                    task.postCommit(true);
   772→                }
   773→            } catch (final RuntimeException e) {
   774→                final String uncleanMessage = String.format(
   775→                        "Failed to checkpoint task %s. Attempting to close remaining tasks before re-throwing:",
   776→                        task.id());
   777→                log.error(uncleanMessage, e);
   778→                taskCloseExceptions.putIfAbsent(task.id(), e);
   779→                // We've already recorded the exception (which is the point of clean).
   780→                // Now, we should go ahead and complete the close because a half-closed task is no good to anyone.
   781→                tasksToCloseDirty.add(task);
   782→            }
   783→        }
   784→
   785→        tasksToCloseClean.removeAll(tasksToCloseDirty);
   786→        for (final Task task : tasksToCloseClean) {
   787→            try {
   788→                closeTaskClean(task);
   789→            } catch (final RuntimeException closeTaskException) {
   790→                final String uncleanMessage = String.format(
   791→                    "Failed to close task %s cleanly. Attempting to close remaining tasks before re-throwing:",
   792→                    task.id());
   793→                log.error(uncleanMessage, closeTaskException);
   794→
   795→                if (task.state() != State.CLOSED) {
   796→                    tasksToCloseDirty.add(task);
   797→                }
   798→
   799→                taskCloseExceptions.putIfAbsent(task.id(), closeTaskException);
   800→            }
   801→        }
   802→
   803→        tasksToRecycle.keySet().removeAll(tasksToCloseDirty);
   804→        for (final Map.Entry<Task, Set<TopicPartition>> entry : tasksToRecycle.entrySet()) {
   805→            final Task oldTask = entry.getKey();
   806→            final Set<TopicPartition> inputPartitions = entry.getValue();
   807→            try {
   808→                if (oldTask.isActive()) {
   809→                    final StandbyTask standbyTask = convertActiveToStandby((StreamTask) oldTask, inputPartitions);
   810→                    if (stateUpdater != null) {
   811→                        tasks.removeTask(oldTask);
   812→                        tasks.addPendingTasksToInit(Collections.singleton(standbyTask));
   813→                    } else {
   814→                        tasks.replaceActiveWithStandby(standbyTask);
   815→                    }
   816→                } else {
   817→                    final StreamTask activeTask = convertStandbyToActive((StandbyTask) oldTask, inputPartitions);
   818→                    tasks.replaceStandbyWithActive(activeTask);
   819→                }
   820→            } catch (final RuntimeException e) {
   821→                final String uncleanMessage = String.format("Failed to recycle task %s cleanly. " +
   822→                    "Attempting to close remaining tasks before re-throwing:", oldTask.id());
   823→                log.error(uncleanMessage, e);
   824→                taskCloseExceptions.putIfAbsent(oldTask.id(), e);
   825→                tasksToCloseDirty.add(oldTask);
   826→            }
   827→        }
   828→
   829→        // for tasks that cannot be cleanly closed or recycled, close them dirty
   830→        for (final Task task : tasksToCloseDirty) {
   831→            closeTaskDirty(task, true);
   832→        }
   833→
   834→        return taskCloseExceptions;
   835→    }
